               (sel.startsWith('#') ? document.getElementById(sel.slice(1)) : null);
    if (!el) return { error: `Element not found: ${sel}`, selector: sel };

    const result = {
      tag: el.tagName,
      type: el.type || el.getAttribute('role') || el.tagName,
