      name: el.name,
      value: el.value || '',
      placeholder: el.placeholder || '',
      disabled: el.disabled || false,
      role: el.getAttribute('role') || '',
      required: el.hasAttribute('required') || false,
      rect: el.getBoundingClientRect(),
    };

    // Label info
    if (el.labels && el.labels[0]) {
      result.label = el.labels[0].textContent.trim();
    } else {
      const labelEl = document.querySelector(`label[for="${el.id}"]`);
      if (labelEl) result.label = labelEl.textContent.trim();
    }

    // Toggle button (Oracle CX)
    const toggleId = el.id + '-toggle-button';
    const toggle = document.getElementById(toggleId);
    if (toggle) {
      result.toggleButton = {
        exists: true,
        text: (toggle.textContent || '').trim(),
        ariaExpanded: toggle.getAttribute('aria-expanded'),
        visible: toggle.offsetHeight > 0 && toggle.offsetParent !== null,
      };
    }

    // Oracle combobox specific
    if (el.getAttribute('role') === 'combobox' || el.closest('.cx-select') || el.closest('.cx-select-container')) {
      result.isOracleCombobox = true;
      // Check for open dropdown
      const listboxId = el.id + '-listbox';
      const listbox = document.getElementById(listboxId);
      if (listbox) {
        result.dropdownOpen = listbox.offsetHeight > 0 && listbox.offsetParent !== null;
        result.dropdownOptions = Array.from(listbox.querySelectorAll('[role="option"], [role="gridcell"], li, .cx-select__list-item'))
          .map(o => ({
            text: (o.textContent || '').trim(),
            selected: o.getAttribute('aria-selected') === 'true',
          }));
      }
    }

    // Select element options
    if (el.tagName === 'SELECT') {
      result.options = Array.from(el.options).map(o => ({
        text: o.text,
        value: o.value,
        selected: o.selected,
      }));
      result.selectedIndex = el.selectedIndex;
      result.selectedText = el.options[el.selectedIndex]?.text || '';
    }

    // Dataset attributes (jcFilled etc)
    result.dataset = {};
    for (const key of Object.keys(el.dataset)) {
      if (key.startsWith('jc')) result.dataset[key] = el.dataset[key];
    }

    // Validation state
    result.validationMessage = el.validationMessage || '';
    result.validity = el.validity ? {
      badInput: el.validity.badInput,
      customError: el.validity.customError,
      patternMismatch: el.validity.patternMismatch,
      rangeOverflow: el.validity.rangeOverflow,
      rangeUnderflow: el.validity.rangeUnderflow,
      stepMismatch: el.validity.stepMismatch,
      tooLong: el.validity.tooLong,
      tooShort: el.validity.tooShort,
      typeMismatch: el.validity.typeMismatch,
      valid: el.validity.valid,
      valueMissing: el.validity.valueMissing,
    } : null;

    return result;
  }, selector);

  console.log(JSON.stringify(state, null, 2));
  await page.close();
}

function parseArgs(args) {
