import { connect } from '../lib/connect.mjs';
import { writeFileSync } from 'fs';
import { join } from 'path';

export default async function fieldVerify(args) {
  const { pattern, selector, expected, label } = parseArgs(args);
  const { page, context } = await connect(pattern);

  const resultDir = '/tmp/cdc-verify';
  mkdirSync(resultDir, { recursive: true });

  const ts = Date.now();
  const result = {
    field: selector,
    label,
    expected,
    before: null,
    after: null,
    pass: false,
    screenshots: {},
    errors: [],
  };

  try {
    // STEP 1: Read field state BEFORE
    const beforeState = await page.evaluate((sel) => {
      const el = document.querySelector(sel);
      if (!el) return { error: `Element not found: ${sel}` };
      return {
        value: el.value || '',
        toggleText: document.getElementById(el.id + '-toggle-button')?.textContent?.trim() || '',
        ariaExpanded: document.getElementById(el.id + '-toggle-button')?.getAttribute('aria-expanded') || null,
        role: el.getAttribute('role') || '',
        disabled: el.disabled,
      };
    }, selector);
    result.before = beforeState;

    // STEP 2: Screenshot BEFORE
    const beforePath = join(resultDir, `${ts}-${label || 'field'}-before.png`);
    await page.screenshot({ path: beforePath, fullPage: true });
    result.screenshots.before = beforePath;

    // STEP 3: Fill the field
    const fillResult = await page.evaluate((sel, val) => {
      const el = document.querySelector(sel);
      if (!el) return { error: 'Element not found' };

      el.focus();
      el.value = val;
      el.dispatchEvent(new Event('input', { bubbles: true }));
      el.dispatchEvent(new Event('change', { bubbles: true }));
      el.blur();

      return { value: el.value };
    }, selector, expected);

    // Wait for framework to settle
    await new Promise(r => setTimeout(r, 1000));

    // STEP 4: Read field state AFTER
    const afterState = await page.evaluate((sel) => {
      const el = document.querySelector(sel);
      if (!el) return { error: `Element not found: ${sel}` };
      return {
        value: el.value || '',
        toggleText: document.getElementById(el.id + '-toggle-button')?.textContent?.trim() || '',
        ariaExpanded: document.getElementById(el.id + '-toggle-button')?.getAttribute('aria-expanded') || null,
      };
    }, selector);
    result.after = afterState;

    // STEP 5: Screenshot AFTER
    const afterPath = join(resultDir, `${ts}-${label || 'field'}-after.png`);
    await page.screenshot({ path: afterPath, fullPage: true });
    result.screenshots.after = afterPath;

    // STEP 6: Compare
    const beforeVal = (beforeState.value || '').trim().toLowerCase();
    const afterVal = (afterState.value || '').trim().toLowerCase();
    const expVal = (expected || '').trim().toLowerCase();

    if (beforeVal !== afterVal && (afterVal.includes(expVal) || expVal.includes(afterVal))) {
      result.pass = true;
      result.message = `Field filled: "${beforeState.value}" → "${afterState.value}"`;
    } else if (afterVal === expVal) {
      result.pass = true;
      result.message = `Field filled: "${afterState.value}" matches expected`;
    } else if (beforeVal === afterVal && afterVal !== expVal) {
      result.pass = false;
      result.message = `Field NOT filled. Before="${beforeState.value}", After="${afterState.value}", Expected="${expected}"`;
      // Check if Oracle combobox rejected value
      if (afterState.toggleText && !afterState.toggleText.includes(expVal)) {
        result.message += ' — Combobox toggle text does not contain expected value';
      }
    } else {
      result.pass = false;
      result.message = `Value mismatch: expected "${expected}", got "${afterState.value}"`;
    }

  } catch (err) {
    result.pass = false;
    result.errors.push(err.message);
  }

  console.log(JSON.stringify(result, null, 2));

  // Write report
  const reportPath = join(resultDir, `${ts}-report.json`);
  writeFileSync(reportPath, JSON.stringify(result, null, 2));
  console.error(`Report saved: ${reportPath}`);

  await page.close();
  process.exit(result.pass ? 0 : 1);
}

function parseArgs(args) {
  const pattern = args[0] || 'default';
  const selector = args[1];
  const expected = args[2];
  const label = args[3] || selector.replace(/[^a-zA-Z0-9]/g, '_');
  if (!selector || !expected) {
    console.error('Usage: cdc field-verify <page-pattern> <css-selector> <expected-value> [label]');
    process.exit(1);
  }
  return { pattern, selector, expected, label };
}
```

